1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const CURSE_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const FOLLOWUP_DISCOUNT_RATE = 0.15;
23	
24	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
25	  sword: 1000,
26	  amulet: 600,
27	  staff: 800,
28	  potion: 400,
29	  rune: 250,
30	  moonstone: 250,
31	};
32	const DEDUCTIBLE = 100;
33	const CAP_MULTIPLIER = 2;
34	
35	type Item = {
36	  type: string;
37	  material?: string;
38	  enchantment?: number;
39	  cursed?: boolean;
40	};
41	type Damage = { itemType: string; amount: number };
42	type Incident = { cause: string; damages: Damage[] };
43	type QuoteStep = { op: "quote"; items: Item[] };
44	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
45	type Step = QuoteStep | ClaimStep;
46	type Customer = { yearsWithMHPCO: number };
47	type Scenario = { customer: Customer; steps: Step[] };
48	type QuoteResult = { premium: number };
49	type ClaimResult = { payout: number; remainingCap: number };
50	type StepResult = QuoteResult | ClaimResult;
51	
52	const itemBase = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
53	
54	const itemSurcharges = (item: Item): number => {
55	  const base = itemBase(item);
56	  let s = 0;
57	  if (item.cursed) s += base * CURSE_SURCHARGE_RATE;
58	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
59	    s += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
60	  }
61	  s += base * FIRST_INSURANCE_RATE;
62	  return s;
63	};
64	
65	const componentBlockBase = (items: Item[]): number => {
66	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
67	  const counts = new Map<string, number>();
68	  for (const c of components) {
69	    counts.set(c.type, (counts.get(c.type) ?? 0) + 1);
70	  }
71	  let total = 0;
72	  for (const [type, count] of counts.entries()) {
73	    if (count === BLOCK_SIZE) {
74	      total += BLOCK_PREMIUM;
75	    } else {
76	      total += count * itemBase({ type });
77	    }
78	  }
79	  return total;
80	};
81	
82	const policyBase = (items: Item[]): number => {
83	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
84	  const mainBase = mainItems.reduce((sum, item) => sum + itemBase(item), 0);
85	  return mainBase + componentBlockBase(items);
86	};
87	
88	const itemSurchargeTotal = (items: Item[]): number => {
89	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
90	  return mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
91	};
92	
93	const quotePremium = (items: Item[], customer: Customer, priorQuotes: number): number => {
94	  const policyBaseAmount = policyBase(items);
95	  const surcharges = itemSurchargeTotal(items);
96	  let policyAdjustment = 0;
97	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
98	    policyAdjustment -= policyBaseAmount * LOYALTY_DISCOUNT_RATE;
99	  }
100	  if (priorQuotes >= 1) {
101	    policyAdjustment -= policyBaseAmount * FOLLOWUP_DISCOUNT_RATE;
102	  }
103	  const total = policyBaseAmount + surcharges + policyAdjustment + PROCESSING_FEE;
104	  return Math.ceil(total);
105	};
106	
107	const insuranceSum = (items: Item[]): number =>
108	  items.reduce((sum, item) => sum + (INSURANCE_VALUE_BY_TYPE[item.type] ?? 0), 0);
109	
110	type Policy = { items: Item[]; capRemaining: number };
111	
112	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
113	  const totalPayout = incident.damages.reduce(
114	    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
115	    0,
116	  );
117	  const payout = Math.min(totalPayout, policy.capRemaining);
118	  policy.capRemaining -= payout;
119	  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
120	};
121	
122	export const runScenario = (input: Scenario): { results: StepResult[] } => {
123	  let quoteCount = 0;
124	  const policies: Policy[] = [];
125	  const results: StepResult[] = input.steps.map((step) => {
126	    if (step.op === "quote") {
127	      const result: QuoteResult = {
128	        premium: quotePremium(step.items, input.customer, quoteCount),
129	      };
130	      quoteCount++;
131	      policies.push({
132	        items: step.items,
133	        capRemaining: insuranceSum(step.items) * CAP_MULTIPLIER,
134	      });
135	      return result;
136	    }
137	    const policy = policies[step.policy];
138	    return processClaim(policy, step.incident);
139	  });
140	  return { results };
141	};
