const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const claimedAmount = incident.damages.reduce((sum, damage) => sum + damagePayout(damage), 0);
